  & B: SVD (tham chiếu) & --- & 216{,}2 & tham chiếu \\
  & C: Mode A           & --- & 59{,}3  & 27{,}4\,\% \\
  & D: Mode B           & --- & 72{,}1  & 33{,}4\,\% \\
\addlinespace
\multirow{3}{*}{$+10$\,dB (trung bình)}
  & B: SVD (tham chiếu) & --- & 332{,}7 & tham chiếu \\
  & C: Mode A           & --- & 181{,}5 & 54{,}5\,\% \\
  & D: Mode B           & --- & 198{,}1 & 59{,}5\,\% \\
\addlinespace
\multirow{3}{*}{$+25$\,dB (gần)}
  & B: SVD (tham chiếu) & --- & 332{,}7 & tham chiếu \\
  & C: Mode A           & --- & 216{,}2 & 65{,}0\,\% \\
  & D: Mode B           & --- & 233{,}8 & 70{,}3\,\% \\
\bottomrule
\end{tabular}
