    % Initialize outputs
    [RI, PMISet] = initOutputs(reportConfig,PMISubbandInfo);

    % For each valid rank, select the best CQI. Then, find the rank
    % that maximizes modulation and coding efficiency
    maxRank = max(validRanks);

