                ncw = numel(cqiWideband);
                cwLayers = floor((rank + (0:ncw-1)) / ncw);
                mcs = nr5g.internal.nrCQITables(reportConfig.CQITable,cqiWideband);
                eff = cwLayers .* (1 - blerWideband) * mcs(:,4);
                efficiency(rank) = eff;
            end
        else
            efficiency(rank) = 0;
        end
    end

    % Return the rank that maximizes the spectral efficiency and the
    % corresponding PMI.
    [maxEff,RI] = max(efficiency);
    if ~isnan(maxEff)
        PMISet = pmi(RI);
        PMIInfo = pmiInfo(RI);
    end

end

